from __future__ import annotations
from dataclasses import dataclass
from typing import Optional

@dataclass
class EntityMatch:
    golden_id: str
    entity_type: EntityType
    canonical_name: str
    confidence: float   # 0.0 – 1.0
    match_method: str   # "exact_id", "name_lookup", "vector_similarity"

class EntityResolver:
    def __init__(
        self,
        entity_store: "GoldenEntityStore",
        embed_fn,          # text → vector
        vector_index,      # approximate nearest-neighbour index of entity names
        *,
        similarity_threshold: float = 0.85,
    ) -> None:
        self._store = entity_store
        self._embed = embed_fn
        self._index = vector_index
        self._threshold = similarity_threshold

    def resolve(self, mention: str) -> Optional[EntityMatch]:
        # 1. Exact ID match (fastest: mention is a known system ID)
        record = self._store.find_by_alias(mention)
        if record:
            return EntityMatch(
                record.golden_id, record.entity_type,
                record.canonical_name, 1.0, "exact_id"
            )

        # 2. Canonical name lookup (case-insensitive)
        record = self._store.find_by_name(mention.strip().lower())
        if record:
            return EntityMatch(
                record.golden_id, record.entity_type,
                record.canonical_name, 0.95, "name_lookup"
            )

        # 3. Vector similarity on entity name embeddings
        query_vec = self._embed(mention)
        hits = self._index.query(query_vec, top_k=1)
        if hits and hits[0]["score"] >= self._threshold:
            golden_id = hits[0]["id"]
            record = self._store.get(golden_id)
            if record:
                return EntityMatch(
                    record.golden_id, record.entity_type,
                    record.canonical_name, hits[0]["score"], "vector_similarity"
                )
        return None

from __future__ import annotations
from datetime import datetime, timezone
from typing import Callable, Optional

class GoldenEntityStore:
    def __init__(
        self,
        fetch_from_system_of_record: Callable[[str], Optional[GoldenEntityRecord]],
    ) -> None:
        self._cache: dict[str, GoldenEntityRecord] = {}
        self._fetch = fetch_from_system_of_record
        self._alias_index: dict[str, str] = {}  # alias → golden_id
        self._name_index: dict[str, str] = {}   # lower(name) → golden_id

    def upsert(self, record: GoldenEntityRecord) -> None:
        self._cache[record.golden_id] = record
        for ref in record.source_refs:
            self._alias_index[ref.external_id] = record.golden_id
        self._name_index[record.canonical_name.lower()] = record.golden_id

    def get(self, golden_id: str) -> Optional[GoldenEntityRecord]:
        record = self._cache.get(golden_id)
        if record is None:
            return None
        if record.is_stale():
            refreshed = self._fetch(golden_id)
            if refreshed:
                self.upsert(refreshed)
                return refreshed
        return record

    def find_by_alias(self, external_id: str) -> Optional[GoldenEntityRecord]:
        gid = self._alias_index.get(external_id)
        return self.get(gid) if gid else None

    def find_by_name(self, lower_name: str) -> Optional[GoldenEntityRecord]:
        gid = self._name_index.get(lower_name)
        return self.get(gid) if gid else None

    def get_for_context(self, golden_id: str, requesting_app: str) -> Optional[str]:
        """Return context snippet if the app is permitted; None otherwise."""
        record = self.get(golden_id)
        if record is None:
            return None
        if requesting_app not in record.permitted_apps:
            return None
        return record.to_context_snippet()
